external_knowledge:
; The "top 5 most frequently accessed cables" refers to the cables with the highest access counts in the access_logs table; 
; "rated voltage" and "rated current" are electrical properties of cables that indicate their maximum allowed voltage and current, respectively; 
; "AC resistance", "reactance", and "inductance" are electrical properties of cables that describe their behavior under alternating current conditions.

sql:
SELECT cable_id
FROM cables
ORDER BY cable_id;

SELECT COUNT(document_id) AS total_documents
FROM cable_documents
WHERE cable_id = 1;

SELECT COUNT(*) AS document_count
FROM cable_documents
WHERE cable_id = (SELECT cable_id FROM cables WHERE name = 'BD-FPE AL2-4x6 0.60 kV');

SELECT cable_id, COUNT(document_id) AS total_documents
FROM cable_documents
GROUP BY cable_id;
